import React, { useState } from "react";
import HomePage from "./HomePage";

// FriendList component
const FriendList = () => {
  const friends = ["Nguyễn Văn A", "Nguyễn Văn B", "Nguyễn Văn C"];
  const suggestions = ["Trần Thị X", "Lê Văn Y", "Phạm Thị Z"];

  return (
    <div className="flex gap-6 p-6 mt-6">
      {/* Danh sách bạn bè */}
      <div className="flex-1 flex flex-col gap-2">
        <h2 className="text-2xl font-bold mb-3">Danh sách bạn bè</h2>
        {friends.map((name, idx) => (
          <div
            key={idx}
            className="flex items-center gap-4 bg-[#A2D3FF] p-3 rounded-lg"
          >
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
              className="w-[90px] h-20 object-fill"
            />
            <span className="text-black text-2xl flex-1">{name}</span>
            <button className="bg-white px-3 py-1 rounded-lg">Delete</button>
            <button className="bg-[#F6FEFF] px-3 py-1 rounded-lg">Follow</button>
          </div>
        ))}
      </div>

      {/* Gợi ý kết bạn */}
      <div className="w-[300px] flex flex-col gap-3">
        <h2 className="text-2xl font-bold mb-3">Gợi ý kết bạn</h2>
        {suggestions.map((name, idx) => (
          <div
            key={idx}
            className="flex items-center gap-4 bg-[#F0F8FF] p-3 rounded-lg"
          >
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
              className="w-[60px] h-16 object-fill"
            />
            <span className="flex-1 text-black text-xl">{name}</span>
            <button className="bg-[#88BCF8] text-white px-3 py-1 rounded-lg">
              Thêm bạn
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

export default function App() {
  const [screen, setScreen] = useState("home"); // home | friendlist
  const [input1, setInput1] = useState("");

  return (
    <div className="flex">

{/* Sidebar cố định */}
<div className="fixed left-0 top-[160px] w-[88px] flex flex-col items-center bg-[#88BCF8] py-4 px-[23px] gap-[25px] z-50 shadow-md rounded-r-xl">
  <img
    src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/yrrmpwtt_expires_30_days.png"
    className="w-[42px] h-[42px] cursor-pointer"
    onClick={() => setScreen("home")}
  />
  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/quq81c0l_expires_30_days.png" className="w-[42px] h-[42px] cursor-pointer" />
  <img
    src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/31c1kzbw_expires_30_days.png"
    className="w-[42px] h-[37px] cursor-pointer"
    onClick={() => setScreen("friendlist")}
  />
  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/3deuzw7r_expires_30_days.png" className="w-[42px] h-[42px] cursor-pointer" />
  <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/6ebyucyr_expires_30_days.png" className="w-[42px] h-[42px] cursor-pointer" />
</div>

      {/* Nội dung trang */}
      <div className="flex-1 ml-[88px]">
        {/* Header cố định */}
        <div className="fixed top-0 left-0 right-0 flex items-center justify-between bg-[#88BCF8] py-3 px-6 z-50 shadow-md">
          <div className="flex items-center flex-shrink-0">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"
              className="w-[120px] h-[110px] object-fill"
            />
          </div>

          <div className="flex-1 mx-6 max-w-[600px]">
            <input
              placeholder="Nhập để tìm kiếm"
              value={input1}
              onChange={(e) => setInput1(e.target.value)}
              className="text-black bg-[#F6FEFF] text-base w-full py-2 px-5 rounded-[50px] border-0"
            />
          </div>

          <div className="flex items-center gap-4 flex-shrink-0">
          <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/quq81c0l_expires_30_days.png" className="w-[50px] h-[38px]" alt="search-icon" />
          <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/quq81c0l_expires_30_days.png" className="w-[42px] h-[42px] cursor-pointer" />
          <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/31c1kzbw_expires_30_days.png" className="w-[42px] h-[37px] cursor-pointer" onClick={() => setScreen("friendlist")} />
          <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/3deuzw7r_expires_30_days.png" className="w-[42px] h-[42px] cursor-pointer" />
          <img src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/6ebyucyr_expires_30_days.png" className="w-[42px] h-[42px] cursor-pointer" />
      </div>
        </div>

        {/* Nội dung chính với animation */}
        <div className="mt-[140px] transition-all duration-300">
          {screen === "home" && <HomePage />}
          {screen === "friendlist" && <FriendList />}
        </div>
      </div>
    </div>
  );
}
